```typescript
import { NextRequest } from 'next/server';
import { streamText } from 'ai';
import { openai } from '@ai-sdk/openai';
import { z } from 'zod';
import { withAuth } from '@/lib/auth';
import { chatHistory } from '@/lib/ai/chat-history';
import { buildSystemPrompt } from '@/lib/ai/system-prompts';
import { createTools } from './tools';
import { ChatRequest, Message } from '@/types/chat';
import { redis } from '@/lib/queue';

const chatRequestSchema = z.object({
  message: z.string().min(1).max(2000),
  conversationId: z.string().uuid().optional(),
  context: z.object({
    pageType: z.enum(['monitor-detail', 'dashboard', 'incidents', 'incident-detail', 'validators', 'escalation-policies']).nullable(),
    monitorId: z.string().uuid().optional(),
    incidentId: z.string().uuid().optional(),
    escalationPolicyId: z.string().uuid().optional(),
  }).optional(),
});

const RATE_LIMIT_WINDOW = 60; // 1 minute
const RATE_LIMIT_MAX = parseInt(process.env.CHAT_RATE_LIMIT_PER_MINUTE || '20');

export const POST = withAuth(async (req: NextRequest, user, session) => {
  try {
    // Rate limiting
    const rateLimitKey = `ratelimit:chat:${user.id}`;
    const requestCount = await redis.incr(rateLimitKey);

    if (requestCount === 1) {
      await redis.expire(rateLimitKey, RATE_LIMIT_WINDOW);
    }

    if (requestCount > RATE_LIMIT_MAX) {
      return Response.json(
        { error: 'Too many messages. Please wait a moment before sending more.' },
        { status: 429 }
      );
    }

    // Parse and validate request
    const body = await req.json();
    const validation = chatRequestSchema.safeParse(body);

    if (!validation.success) {
      return Response.json(
        { error: validation.error.message },
        { status: 400 }
      );
    }

    const { message, conversationId, context } = validation.data;

    // Load or create conversation
    let conversation;
    let activeConversationId = conversationId;

    if (conversationId) {
      conversation = await chatHistory.loadConversation(user.id, conversationId);
      if (!conversation) {
        return Response.json(
          { error: 'Conversation not found' },
          { status: 404 }
        );
      }
    } else {
      activeConversationId = await chatHistory.createConversation(user.id);
      conversation = await chatHistory.loadConversation(user.id, activeConversationId);
    }

    // Build message history for LLM
    const systemPrompt = buildSystemPrompt({ context });
    const messageHistory = conversation!.messages.map(msg => ({
      role: msg.role,
      content: msg.content,
      experimental_toolCalls: msg.toolCalls,
      experimental_toolResults: msg.toolResults,
    }));

    // Create tools with execution context
    const tools = createTools({
      userId: user.id,
      sessionId: session.id,
      context,
    });

    // Stream response
    const model = process.env.OPENAI_MODEL || 'gpt-4o';
    const result = streamText({
      model: openai(model),
      system: systemPrompt,
      messages: [
        ...messageHistory,
        { role: 'user', content: message },
      ],
      tools,
      maxSteps: 5, // Allow up to 5 tool calls in sequence
      temperature: 1.0,
      onFinish: async ({ text, toolCalls, toolResults }) => {
        // Save conversation after completion
        const userMessage: Message = {
          role: 'user',
          content: message,
          timestamp: new Date().toISOString(),
        };

        const assistantMessage: Message = {
          role: 'assistant',
          content: text,
          toolCalls,
          toolResults,
          timestamp: new Date().toISOString(),
        };

        await chatHistory.appendMessage(user.id, activeConversationId!, userMessage);
        await chatHistory.appendMessage(user.id, activeConversationId!, assistantMessage);
      },
    });

    // Return SSE stream with conversation ID in headers
    return result.toDataStreamResponse({
      headers: {
        'X-Conversation-Id': activeConversationId!,
      },
    });
  } catch (error) {
    console.error('Chat API error:', error);
    return Response.json(
      { error: 'Internal server error' },
      { status: 500 }
    );
  }
});
```

Implementation notes:
- Uses toDataStreamResponse() (AI SDK 5.0 pattern, replaces StreamingTextResponse)
- maxSteps: 5 enables multi-tool execution (agentic behavior)
- Rate limiting prevents abuse and controls OpenAI costs
- onFinish callback saves conversation after streaming completes
- Returns X-Conversation-Id header for client to track conversation
- Reference: https://vercel.com/blog/ai-sdk-5
- Reference: https://hackernoon.com/streaming-in-nextjs-15-websockets-vs-server-sent-events

