```typescript
'use client';

import { useState, useCallback, useRef } from 'react';
import { useMutation, useQueryClient } from '@tanstack/react-query';
import { Message, ChatRequest, PageContext } from '@/types/chat';
import { useChatContext } from '@/providers/chat-context-provider';

interface UseChatOptions {
  onError?: (error: Error) => void;
}

export function useChat(options: UseChatOptions = {}) {
  const [messages, setMessages] = useState<Message[]>([]);
  const [isStreaming, setIsStreaming] = useState(false);
  const [conversationId, setConversationId] = useState<string | undefined>();
  const abortControllerRef = useRef<AbortController | null>(null);
  const { context } = useChatContext();
  const queryClient = useQueryClient();

  const sendMessage = useMutation({
    mutationFn: async (messageContent: string) => {
      // Abort any existing stream
      if (abortControllerRef.current) {
        abortControllerRef.current.abort();
      }

      abortControllerRef.current = new AbortController();
      setIsStreaming(true);

      // Add user message immediately
      const userMessage: Message = {
        role: 'user',
        content: messageContent,
        timestamp: new Date().toISOString(),
      };
      setMessages(prev => [...prev, userMessage]);

      // Prepare request
      const requestBody: ChatRequest = {
        message: messageContent,
        conversationId,
        context,
      };

      // Send request
      const response = await fetch('/api/chat', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        credentials: 'include',
        body: JSON.stringify(requestBody),
        signal: abortControllerRef.current.signal,
      });

      if (!response.ok) {
        const error = await response.json();
        throw new Error(error.error || 'Failed to send message');
      }

      // Get conversation ID from headers
      const newConversationId = response.headers.get('X-Conversation-Id');
      if (newConversationId) {
        setConversationId(newConversationId);
      }

      // Stream response
      const reader = response.body?.getReader();
      const decoder = new TextDecoder();
      let assistantMessage = '';

      if (!reader) {
        throw new Error('No response stream');
      }

      while (true) {
        const { done, value } = await reader.read();
        if (done) break;

        const chunk = decoder.decode(value, { stream: true });
        const lines = chunk.split('\n').filter(line => line.trim());

        for (const line of lines) {
          if (line.startsWith('data: ')) {
            const data = line.slice(6);
            if (data === '[DONE]') continue;

            try {
              const parsed = JSON.parse(data);
              if (parsed.type === 'text-delta') {
                assistantMessage += parsed.textDelta;
                // Update streaming message
                setMessages(prev => {
                  const withoutLast = prev.slice(0, -1);
                  const lastMessage = prev[prev.length - 1];
                  if (lastMessage?.role === 'assistant') {
                    return [...withoutLast, { ...lastMessage, content: assistantMessage }];
                  }
                  return [...prev, {
                    role: 'assistant' as const,
                    content: assistantMessage,
                    timestamp: new Date().toISOString(),
                  }];
                });
              }
            } catch (e) {
              console.error('Failed to parse SSE data:', e);
            }
          }
        }
      }

      setIsStreaming(false);
      return { conversationId: newConversationId };
    },
    onError: (error: Error) => {
      setIsStreaming(false);
      options.onError?.(error);

      // Add error message to chat
      setMessages(prev => [...prev, {
        role: 'assistant',
        content: `Error: ${error.message}`,
        timestamp: new Date().toISOString(),
      }]);
    },
  });

  const clearMessages = useCallback(() => {
    setMessages([]);
    setConversationId(undefined);
  }, []);

  const stopStreaming = useCallback(() => {
    if (abortControllerRef.current) {
      abortControllerRef.current.abort();
      setIsStreaming(false);
    }
  }, []);

  return {
    messages,
    isStreaming,
    conversationId,
    sendMessage: sendMessage.mutate,
    isLoading: sendMessage.isPending,
    error: sendMessage.error,
    clearMessages,
    stopStreaming,
  };
}
```

Implementation notes:
- Uses TanStack Query's useMutation for state management
- Handles SSE streaming with ReadableStream API
- Auto-scrolls by updating messages during streaming
- AbortController enables stopping mid-stream
- Integrates with ChatContext for automatic context injection
- Reference: https://tanstack.com/query/latest/docs/framework/react/guides/queries
- Reference: https://upstash.com/blog/sse-streaming-llm-responses

