'use client';

import { useEffect, useState } from 'react';
import { Alert, AlertDescription } from '@/components/ui/alert';
import { Clock } from 'lucide-react';

interface RateLimitWarningProps {
  messageCount: number;
}

export function RateLimitWarning({ messageCount }: RateLimitWarningProps) {
  const [show, setShow] = useState(false);

  useEffect(() => {
    if (messageCount >= 15 && messageCount < 20) {
      setShow(true);
    } else {
      setShow(false);
    }
  }, [messageCount]);

  if (!show) return null;

  return (
    <Alert className="mx-4 mt-4">
      <Clock className="h-4 w-4" />
      <AlertDescription>
        You've sent {messageCount}/20 messages. Rate limit: 20 messages per minute.
      </AlertDescription>
    </Alert>
  );
}
